import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused } from './stores/game';
import { gameSession } from './stores/game-session';
import { timer } from './stores/timer';
import { hints } from './stores/hints';

export function startNew(diff) {
	difficulty.set(diff);
	gameSession.startNew(diff);
	cursor.reset();
	timer.reset();
	hints.reset();
	location.hash = '';
}

export function startCustom(sencode) {
	difficulty.setCustom();
	gameSession.startCustom(sencode);
	cursor.reset();
	timer.reset();
	hints.reset();
	location.hash = sencode ? `#${sencode}` : '';
}

export function pauseGame() {
	timer.stop();
	gamePaused.set(true);
}

export function resumeGame() {
	timer.start();
	gamePaused.set(false);
}

export default {
	startNew,
	startCustom,
	pause: pauseGame,
	resume: resumeGame,
};
